/**
 * Query Executor
 * Safely executes SQL queries generated by the AI Query Planner
 */

import { createClient } from '@supabase/supabase-js';
import type { QueryPlan } from './query-planner';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY!;

export interface QueryResult {
  success: boolean;
  data?: any[];
  error?: string;
  rowCount?: number;
}

/**
 * Execute a query plan with proper school_id and user context
 */
export async function executeQueryPlan(
  queryPlan: QueryPlan,
  schoolId: string,
  userId?: string
): Promise<QueryResult> {
  try {
    // Validate query
    if (queryPlan.error) {
      return {
        success: false,
        error: queryPlan.error
      };
    }

    if (!queryPlan.query) {
      return {
        success: false,
        error: 'No query provided'
      };
    }

    // Replace placeholder values
    const values = queryPlan.values.map(val => {
      if (val === '<school_id>') return schoolId;
      if (val === '<user_id>') return userId;
      return val;
    });

    // Create Supabase client with service role for RPC
    const supabase = createClient(supabaseUrl, supabaseServiceKey);

    // Execute query using Supabase's rpc function
    const { data, error } = await supabase.rpc('execute_ai_query', {
      query_text: queryPlan.query,
      query_params: values
    });

    if (error) {
      console.error('Query execution error:', error);
      return {
        success: false,
        error: error.message || 'Query execution failed'
      };
    }

    return {
      success: true,
      data: data || [],
      rowCount: data?.length || 0
    };
  } catch (error) {
    console.error('Error executing query:', error);
    return {
      success: false,
      error: error instanceof Error ? error.message : 'Unknown error'
    };
  }
}

/**
 * Execute a raw parameterized query (for testing/debugging)
 * Only available in development mode
 */
export async function executeRawQuery(
  query: string,
  values: any[],
  schoolId: string
): Promise<QueryResult> {
  if (process.env.NODE_ENV === 'production') {
    return {
      success: false,
      error: 'Raw queries not allowed in production'
    };
  }

  try {
    const supabase = createClient(supabaseUrl, supabaseServiceKey);

    const { data, error } = await supabase.rpc('execute_ai_query', {
      query_text: query,
      query_params: [schoolId, ...values]
    });

    if (error) {
      return {
        success: false,
        error: error.message
      };
    }

    return {
      success: true,
      data: data || [],
      rowCount: data?.length || 0
    };
  } catch (error) {
    return {
      success: false,
      error: error instanceof Error ? error.message : 'Unknown error'
    };
  }
}
